cy.get('button[type="submit"]').click();
// Success message appears
cy.get('.bg-green-50.text-green-700').should('be.visible').and('contain', 'Doctor account created successfully');
// After 1 second redirects to /doctors-dashboard
cy.url().should('include', '/doctors-dashboard', {
  timeout: 5000
});

cy.intercept('GET', '**/api/doctors/availability*').as('getDoctors');
cy.visit('/book-appointment');
// Dynamic future date
const futureDate = new Date();
futureDate.setDate(futureDate.getDate() + 7);
const formattedDate = futureDate.toISOString().split('T')[0];
cy.get('input[type="date"]').type(formattedDate);
cy.get('input[type="time"]').type('10:00');
// Wait for API
cy.wait('@getDoctors');
// Select real available doctor
cy.get('select option', {
  timeout: 10000
}).should('exist').then($options => {
  const options = [...$options];
  const validDoctors = options.filter(option => option.value !== '' && !option.disabled && !option.text.includes('Choose a doctor') && !option.text.includes('No doctors available') && !option.text.includes('Loading'));
  expect(validDoctors.length).to.be.greaterThan(0);
  cy.get('select').select(validDoctors[0].value);
});
// Fill form
cy.get('input[placeholder*="General checkup"]').type('General checkup visit');
cy.get('textarea').type('No additional notes.');
// Submit
cy.contains('button', 'Request Appointment').click();
// Verify success
cy.contains('successfully', {
  timeout: 10000
}).should('be.visible');

// This is a public route — no login needed
cy.visit('/staff');
// Page must load successfully
cy.url().should('include', '/staff');
// Wait for doctors to load from API (allow up to 10 seconds)
cy.get('body').should('be.visible');
// The page should not show an error state
cy.contains('Error').should('not.exist');

cy.loginAs('patient');
cy.visit('/');
cy.contains('Logout').click();
// Verify token removed
cy.window().then(win => {
  expect(win.localStorage.getItem('token')).to.be.null;
});
// Verify user sees login option again
cy.contains(/login|sign in/i).should('be.visible');

cy.loginAs('patient');
cy.contains('Logout').click();
cy.visit('/book-appointment');
// User should be redirected to login
cy.url().should('include', '/login');
cy.contains(/login/i).should('be.visible');

cy.fixture('users').then(users => {
  cy.get('[name="email"]').type(users.patient.email);
  cy.get('[name="password"]').type(users.patient.password);
  cy.get('button[type="submit"]').click();
  // After login, app navigates to '/' (Home)
  cy.url().should('eq', Cypress.config().baseUrl + '/');
  // Token must be stored in localStorage
  cy.window().then(win => {
    expect(win.localStorage.getItem('token')).to.not.be.null;
    expect(win.localStorage.getItem('role')).to.eq('PATIENT');
  });
});

